2316   Value *NewA = Builder.CreateBinaryIntrinsic(Intrinsic::usub_sat, A, Adj1);
2317   Value *NewB = Builder.CreateBinaryIntrinsic(Intrinsic::usub_sat, B, Adj2);
2318   Value *Or = Builder.CreateOr(NewA, NewB);
2319   Constant *MSBConst = ConstantInt::get(Ty, MostSignificantBit);
